dashboard.definition:
{
	"title": "Cisco Ecosystem Intelligence",
	"description": "Comprehensive Cisco ecosystem analytics — product catalog health, Splunkbase intelligence, deployment readiness, and compliance",
	"inputs": {
		"input_min_version": {
			"type": "input.dropdown",
			"options": {
				"items": [
					{"label": "Splunk 10.4", "value": "10_4"},
					{"label": "Splunk 10.3", "value": "10_3"},
					{"label": "Splunk 10.2", "value": "10_2"},
					{"label": "Splunk 10.1", "value": "10_1"},
					{"label": "Splunk 10.0", "value": "10_0"},
					{"label": "Splunk 9.4", "value": "9_4"},
					{"label": "Splunk 9.3", "value": "9_3"},
					{"label": "Splunk 9.2", "value": "9_2"}
				],
				"defaultValue": "10_2",
				"token": "min_splunk_ver"
			},
			"title": "Minimum Splunk Version"
		}
	},
	"defaults": {
		"dataSources": {
			"ds.search": {
				"options": {
					"queryParameters": {
						"earliest": "-15m",
						"latest": "now"
					}
				}
			}
		}
	},
	"visualizations": {
		"viz_header_health": {
			"options": {
				"markdown": "### Ecosystem Health\nCisco product catalog rollup — 79 products across Security, Networking, Observability, and Collaboration"
			},
			"type": "splunk.markdown"
		},
		"viz_kpi_total": {
			"dataSources": {
				"primary": "ds_kpi_total_products"
			},
			"options": {
				"backgroundColor": "#ebfbff",
				"majorColor": "#027494",
				"sparklineDisplay": "off",
				"trendDisplay": "off",
				"unit": "products",
				"unitPosition": "after"
			},
			"title": "Total Products",
			"type": "splunk.singlevalue"
		},
		"viz_kpi_active": {
			"dataSources": {
				"primary": "ds_kpi_active"
			},
			"options": {
				"backgroundColor": "#e3f7da",
				"majorColor": "#3D851C",
				"sparklineDisplay": "off",
				"trendDisplay": "off",
				"unit": "active",
				"unitPosition": "after"
			},
			"title": "Active Products",
			"type": "splunk.singlevalue"
		},
		"viz_kpi_sourcetypes": {
			"dataSources": {
				"primary": "ds_kpi_sourcetypes"
			},
			"options": {
				"backgroundColor": "#e0eeff",
				"majorColor": "#0A60FF",
				"sparklineDisplay": "off",
				"trendDisplay": "off",
				"unit": "sourcetypes",
				"unitPosition": "after"
			},
			"title": "Total Sourcetypes",
			"type": "splunk.singlevalue"
		},
		"viz_kpi_families": {
			"dataSources": {
				"primary": "ds_kpi_addon_families"
			},
			"options": {
				"backgroundColor": "#ebfbff",
				"majorColor": "#027494",
				"sparklineDisplay": "off",
				"trendDisplay": "off",
				"unit": "families",
				"unitPosition": "after"
			},
			"title": "Add-on Families",
			"type": "splunk.singlevalue"
		},
		"viz_kpi_viz": {
			"dataSources": {
				"primary": "ds_kpi_viz_apps"
			},
			"options": {
				"backgroundColor": "#e0eeff",
				"majorColor": "#0A60FF",
				"sparklineDisplay": "off",
				"trendDisplay": "off",
				"unit": "products",
				"unitPosition": "after"
			},
			"title": "With Viz Apps",
			"type": "splunk.singlevalue"
		},
		"viz_kpi_soar": {
			"dataSources": {
				"primary": "ds_kpi_soar"
			},
			"options": {
				"backgroundColor": "#e0eeff",
				"majorColor": "#0A60FF",
				"sparklineDisplay": "off",
				"trendDisplay": "off",
				"unit": "products",
				"unitPosition": "after"
			},
			"title": "SOAR-Enabled",
			"type": "splunk.singlevalue"
		},
		"viz_kpi_alert": {
			"dataSources": {
				"primary": "ds_kpi_alert_actions"
			},
			"options": {
				"backgroundColor": "#fff8f0",
				"majorColor": "#d97a00",
				"sparklineDisplay": "off",
				"trendDisplay": "off",
				"unit": "products",
				"unitPosition": "after"
			},
			"title": "Alert Actions",
			"type": "splunk.singlevalue"
		},
		"viz_kpi_legacy": {
			"dataSources": {
				"primary": "ds_kpi_legacy"
			},
			"options": {
				"backgroundColor": "#fff4d1",
				"majorColor": "#a16205",
				"sparklineDisplay": "off",
				"trendDisplay": "off",
				"unit": "to migrate",
				"unitPosition": "after"
			},
			"title": "Legacy Apps",
			"type": "splunk.singlevalue"
		},
		"viz_kpi_deprecated": {
			"dataSources": {
				"primary": "ds_kpi_deprecated"
			},
			"options": {
				"backgroundColor": "#ffe8ea",
				"majorColor": "#d91821",
				"sparklineDisplay": "off",
				"trendDisplay": "off",
				"unit": "products",
				"unitPosition": "after"
			},
			"title": "Deprecated",
			"type": "splunk.singlevalue"
		},
		"viz_header_portfolio": {
			"options": {
				"markdown": "### Portfolio Analysis\nCategory distribution, lifecycle status, and support level across the Cisco product catalog"
			},
			"type": "splunk.markdown"
		},
		"viz_pie_category": {
			"dataSources": {
				"primary": "ds_chart_category"
			},
			"options": {
				"seriesColors": [
					"#0A60FF",
					"#3D851C",
					"#0A60FF",
					"#d97a00"
				],
				"showDonutHole": true
			},
			"title": "Products by Category",
			"type": "splunk.pie"
		},
		"viz_col_status": {
			"dataSources": {
				"primary": "ds_chart_status"
			},
			"options": {
				"dataValuesDisplay": "all",
				"seriesColors": [
					"#027494"
				],
				"xAxisTitleVisibility": "hide",
				"yAxisTitleVisibility": "hide"
			},
			"title": "Products by Status",
			"type": "splunk.column"
		},
		"viz_col_support": {
			"dataSources": {
				"primary": "ds_chart_support"
			},
			"options": {
				"dataValuesDisplay": "all",
				"seriesColors": [
					"#027494"
				],
				"xAxisTitleVisibility": "hide",
				"yAxisTitleVisibility": "hide"
			},
			"title": "Support Level",
			"type": "splunk.column"
		},
		"viz_header_soar": {
			"options": {
				"markdown": "### SOAR Connector Inventory\nCisco products with Splunk SOAR automation connectors — identify automation opportunities across your Cisco estate"
			},
			"type": "splunk.markdown"
		},
		"viz_table_soar": {
			"dataSources": {
				"primary": "ds_table_soar"
			},
			"options": {
				"count": 20,
				"dataOverlayMode": "none",
				"drilldown": "none",
				"showRowNumbers": true,
				"tableFormat": {
					"headerBackgroundColor": "#E8EDF2",
					"headerFontColor": "#314257",
					"rowBackgroundColors": "> table | seriesByIndex(0) | pick(#f9fafb,#ffffff)"
				}
			},
			"title": "Products with SOAR Connectors",
			"type": "splunk.table"
		},
		"viz_header_addon_family": {
			"options": {
				"markdown": "### Add-on Family Overview\nProducts grouped by shared Splunk add-on — multiple Cisco products often share a single TA for data collection"
			},
			"type": "splunk.markdown"
		},
		"viz_table_addon_family": {
			"dataSources": {
				"primary": "ds_table_addon_family"
			},
			"options": {
				"count": 25,
				"dataOverlayMode": "none",
				"drilldown": "none",
				"showRowNumbers": true,
				"tableFormat": {
					"headerBackgroundColor": "#E8EDF2",
					"headerFontColor": "#314257",
					"rowBackgroundColors": "> table | seriesByIndex(0) | pick(#f9fafb,#ffffff)"
				}
			},
			"title": "Add-on Families & Shared Products",
			"type": "splunk.table"
		},
		"viz_header_quality": {
			"options": {
				"markdown": "### Data Quality Audit\nProducts with missing critical fields in the SCAN catalog — run after catalog edits to catch data quality issues"
			},
			"type": "splunk.markdown"
		},
		"viz_table_quality": {
			"dataSources": {
				"primary": "ds_table_quality"
			},
			"options": {
				"count": 30,
				"dataOverlayMode": "none",
				"drilldown": "none",
				"showRowNumbers": true,
				"tableFormat": {
					"headerBackgroundColor": "#E8EDF2",
					"headerFontColor": "#314257",
					"rowBackgroundColors": "> table | seriesByIndex(0) | pick(#f9fafb,#ffffff)"
				}
			},
			"title": "Missing Fields Audit",
			"type": "splunk.table"
		},
		"viz_header_splunkbase": {
			"options": {
				"markdown": "### Cisco Splunkbase Intelligence\nApp freshness, platform compatibility, and download analytics for the Cisco ecosystem apps on Splunkbase — filtered exclusively to apps referenced in the SCAN product catalog"
			},
			"type": "splunk.markdown"
		},
		"viz_kpi_live_apps": {
			"dataSources": {
				"primary": "ds_kpi_cisco_live"
			},
			"options": {
				"backgroundColor": "#e3f7da",
				"majorColor": "#3D851C",
				"sparklineDisplay": "off",
				"trendDisplay": "off",
				"unit": "live",
				"unitPosition": "after"
			},
			"title": "Cisco Apps (Live)",
			"type": "splunk.singlevalue"
		},
		"viz_kpi_archived_apps": {
			"dataSources": {
				"primary": "ds_kpi_cisco_archived"
			},
			"options": {
				"backgroundColor": "#ffe8ea",
				"majorColor": "#d91821",
				"sparklineDisplay": "off",
				"trendDisplay": "off",
				"unit": "archived",
				"unitPosition": "after"
			},
			"title": "Cisco Apps (Archived)",
			"type": "splunk.singlevalue"
		},
		"viz_kpi_total_downloads": {
			"dataSources": {
				"primary": "ds_kpi_cisco_downloads"
			},
			"options": {
				"backgroundColor": "#e0eeff",
				"majorColor": "#0A60FF",
				"sparklineDisplay": "off",
				"trendDisplay": "off",
				"unit": "downloads",
				"unitPosition": "after"
			},
			"title": "Total Downloads",
			"type": "splunk.singlevalue"
		},
		"viz_pie_freshness": {
			"dataSources": {
				"primary": "ds_cisco_freshness"
			},
			"options": {
				"seriesColors": [
					"#5cad37",
					"#e5ac00",
					"#FF9000",
					"#d91821"
				],
				"showDonutHole": true
			},
			"title": "Cisco App Freshness",
			"type": "splunk.pie"
		},
		"viz_pie_platform": {
			"dataSources": {
				"primary": "ds_cisco_platform"
			},
			"options": {
				"seriesColors": [
					"#027494",
					"#0A60FF",
					"#3D851C",
					"#a1a9b2"
				],
				"showDonutHole": true
			},
			"title": "Platform Compatibility",
			"type": "splunk.pie"
		},
		"viz_bar_downloads": {
			"dataSources": {
				"primary": "ds_cisco_top_downloads"
			},
			"options": {
				"dataValuesDisplay": "all",
				"seriesColors": [
					"#027494"
				],
				"xAxisTitleVisibility": "hide",
				"yAxisTitleVisibility": "hide"
			},
			"title": "Top 10 Cisco Apps by Downloads",
			"type": "splunk.bar"
		},
		"viz_header_installed": {
			"options": {
				"markdown": "### Installed Cisco Estate\nLocally installed Splunk apps cross-referenced against the Cisco product catalog — shows add-on deployment status and legacy TA presence"
			},
			"type": "splunk.markdown"
		},
		"viz_table_installed": {
			"dataSources": {
				"primary": "ds_table_installed"
			},
			"options": {
				"count": 50,
				"dataOverlayMode": "none",
				"drilldown": "none",
				"showRowNumbers": true,
				"tableFormat": {
					"headerBackgroundColor": "#E8EDF2",
					"headerFontColor": "#314257",
					"rowBackgroundColors": "> table | seriesByIndex(0) | pick(#f9fafb,#ffffff)"
				}
			},
			"title": "Cisco Add-on Deployment Status",
			"type": "splunk.table"
		},
		"viz_header_version": {
			"options": {
				"markdown": "### Version & Update Health\nCisco ecosystem apps sorted by days since last Splunkbase update — identify stale integrations requiring attention"
			},
			"type": "splunk.markdown"
		},
		"viz_table_version": {
			"dataSources": {
				"primary": "ds_cisco_version"
			},
			"options": {
				"count": 25,
				"dataOverlayMode": "none",
				"drilldown": "none",
				"showRowNumbers": true,
				"tableFormat": {
					"headerBackgroundColor": "#E8EDF2",
					"headerFontColor": "#314257",
					"rowBackgroundColors": "> table | seriesByIndex(0) | pick(#f9fafb,#ffffff)"
				}
			},
			"title": "Cisco Apps — Staleness Tracker",
			"type": "splunk.table"
		},
		"viz_header_migration": {
			"options": {
				"markdown": "### Migration Planning\nDeprecated and archived Cisco apps mapped to their modern replacements — essential for planning TA migrations"
			},
			"type": "splunk.markdown"
		},
		"viz_table_migration": {
			"dataSources": {
				"primary": "ds_table_migration"
			},
			"options": {
				"count": 30,
				"dataOverlayMode": "none",
				"drilldown": "none",
				"showRowNumbers": true,
				"tableFormat": {
					"headerBackgroundColor": "#E8EDF2",
					"headerFontColor": "#314257",
					"rowBackgroundColors": "> table | seriesByIndex(0) | pick(#f9fafb,#ffffff)"
				}
			},
			"title": "Deprecated App Migration Paths",
			"type": "splunk.table"
		},
		"viz_header_compliance": {
			"options": {
				"markdown": "### Compliance & Validation\nAppInspect, FedRAMP, and FIPS validation status for Cisco ecosystem apps on Splunkbase"
			},
			"type": "splunk.markdown"
		},
		"viz_table_compliance": {
			"dataSources": {
				"primary": "ds_cisco_compliance"
			},
			"options": {
				"count": 30,
				"dataOverlayMode": "none",
				"drilldown": "none",
				"showRowNumbers": true,
				"tableFormat": {
					"headerBackgroundColor": "#E8EDF2",
					"headerFontColor": "#314257",
					"rowBackgroundColors": "> table | seriesByIndex(0) | pick(#f9fafb,#ffffff)"
				}
			},
			"title": "Cisco Validation & Compliance Status",
			"type": "splunk.table"
		},
		"viz_header_product_version": {
			"options": {
				"markdown": "### Add-on Version Support Analysis\nFor each Cisco/Splunk-supported add-on, which Splunk versions are supported? Select a minimum version to check compatibility. The KPI counts add-ons that declare support for the selected Splunk version."
			},
			"type": "splunk.markdown"
		},
		"viz_kpi_products_supported": {
			"dataSources": {
				"primary": "ds_product_version_kpi"
			},
			"options": {
				"backgroundColor": "#e3f7da",
				"majorColor": "#3D851C",
				"sparklineDisplay": "off",
				"trendDisplay": "off",
				"unit": "add-ons",
				"unitPosition": "after"
			},
			"title": "Compatible Add-ons",
			"type": "splunk.singlevalue"
		},
		"viz_table_product_version": {
			"dataSources": {
				"primary": "ds_product_version_support"
			},
			"options": {
				"count": 50,
				"dataOverlayMode": "none",
				"drilldown": "none",
				"showRowNumbers": true,
				"tableFormat": {
					"headerBackgroundColor": "#E8EDF2",
					"headerFontColor": "#314257",
					"rowBackgroundColors": "> table | seriesByIndex(0) | pick(#f9fafb,#ffffff)"
				}
			},
			"title": "Cisco Add-ons — Splunk Version Support Matrix",
			"type": "splunk.table"
		},
		"viz_table_product_version_gap": {
			"dataSources": {
				"primary": "ds_product_version_gap"
			},
			"options": {
				"count": 50,
				"dataOverlayMode": "none",
				"drilldown": "none",
				"showRowNumbers": true,
				"tableFormat": {
					"headerBackgroundColor": "#E8EDF2",
					"headerFontColor": "#314257",
					"rowBackgroundColors": "> table | seriesByIndex(0) | pick(#f9fafb,#ffffff)"
				}
			},
			"title": "Add-on Version Coverage Gaps (Missing Splunk Version Support)",
			"type": "splunk.table"
		},
		"viz_header_magic6": {
			"options": {
				"markdown": "### Magic Six Audit\nAudits every Cisco product sourcetype against the Magic Six props.conf settings — SHOULD_LINEMERGE, LINE_BREAKER, TRUNCATE, TIME_FORMAT, TIME_PREFIX, MAX_TIMESTAMP_LOOKAHEAD. Identifies gaps that can cause parsing failures, timestamp issues, and data quality problems."
			},
			"type": "splunk.markdown"
		},
		"viz_kpi_magic6_complete": {
			"dataSources": {
				"primary": "ds_magic6_kpi_complete"
			},
			"options": {
				"backgroundColor": "#e3f7da",
				"majorColor": "#3D851C",
				"sparklineDisplay": "off",
				"trendDisplay": "off",
				"unit": "sourcetypes",
				"unitPosition": "after"
			},
			"title": "Complete (6/6)",
			"type": "splunk.singlevalue"
		},
		"viz_kpi_magic6_partial": {
			"dataSources": {
				"primary": "ds_magic6_kpi_partial"
			},
			"options": {
				"backgroundColor": "#fff4d1",
				"majorColor": "#e5ac00",
				"sparklineDisplay": "off",
				"trendDisplay": "off",
				"unit": "sourcetypes",
				"unitPosition": "after"
			},
			"title": "Partial / Minimal",
			"type": "splunk.singlevalue"
		},
		"viz_kpi_magic6_none": {
			"dataSources": {
				"primary": "ds_magic6_kpi_none"
			},
			"options": {
				"backgroundColor": "#ffe8ea",
				"majorColor": "#d91821",
				"sparklineDisplay": "off",
				"trendDisplay": "off",
				"unit": "sourcetypes",
				"unitPosition": "after"
			},
			"title": "No Coverage (0/6)",
			"type": "splunk.singlevalue"
		},
		"viz_chart_magic6_grade": {
			"dataSources": {
				"primary": "ds_magic6_chart_grade"
			},
			"options": {
				"chart": "pie",
				"seriesColors": ["#3D851C", "#e5ac00", "#FF9000", "#d91821"]
			},
			"title": "Compliance Grade Distribution",
			"type": "splunk.pie"
		},
		"viz_chart_magic6_category": {
			"dataSources": {
				"primary": "ds_magic6_chart_category"
			},
			"options": {
				"chart": "column"
			},
			"title": "Avg Magic Six Settings by Category",
			"type": "splunk.column"
		},
		"viz_table_magic6": {
			"dataSources": {
				"primary": "ds_magic6_audit"
			},
			"options": {
				"count": 50,
				"dataOverlayMode": "none",
				"drilldown": "none",
				"showRowNumbers": true,
				"tableFormat": {
					"headerBackgroundColor": "#E8EDF2",
					"headerFontColor": "#314257",
					"rowBackgroundColors": "> table | seriesByIndex(0) | pick(#f9fafb,#ffffff)"
				}
			},
			"title": "Magic Six Compliance — All Cisco Product Sourcetypes",
			"type": "splunk.table"
		}
	},
	"dataSources": {
		"ds_ecosystem_summary": {
			"name": "Ecosystem Summary",
			"options": {
				"query": "| savedsearch \"SCAN - Ecosystem Summary\"",
				"queryParameters": {
					"earliest": "-15m",
					"latest": "now"
				}
			},
			"type": "ds.search"
		},
		"ds_kpi_total_products": {
			"name": "KPI Total Products",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| fields total_products | rename total_products as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_active": {
			"name": "KPI Active Products",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| fields active | rename active as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_sourcetypes": {
			"name": "KPI Sourcetypes",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| fields total_sourcetypes | rename total_sourcetypes as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_addon_families": {
			"name": "KPI Add-on Families",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| fields addon_families | rename addon_families as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_viz_apps": {
			"name": "KPI Viz Apps",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| fields products_with_viz_app | rename products_with_viz_app as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_soar": {
			"name": "KPI SOAR-Enabled",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| fields products_with_soar | rename products_with_soar as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_alert_actions": {
			"name": "KPI Alert Actions",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| fields products_with_alert_action | rename products_with_alert_action as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_legacy": {
			"name": "KPI Legacy Apps",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| fields total_legacy_apps | rename total_legacy_apps as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_deprecated": {
			"name": "KPI Deprecated",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| fields deprecated | rename deprecated as total"
			},
			"type": "ds.chain"
		},
		"ds_chart_category": {
			"name": "Chart Products by Category",
			"options": {
				"query": "| savedsearch \"SCAN - Product Catalog - By Category\" | fields category total | rename total as Count"
			},
			"type": "ds.search"
		},
		"ds_chart_status": {
			"name": "Chart Products by Status",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| eval _r=1 | table _r active deprecated coming_soon | rename active as Active, deprecated as Deprecated, coming_soon as \"Under Development\" | untable _r Status Count | fields Status Count"
			},
			"type": "ds.chain"
		},
		"ds_chart_support": {
			"name": "Chart Support Level",
			"options": {
				"query": "| rest splunk_server=local /servicesNS/-/-/configs/conf-products | fields support_level | eval Support=case(support_level==\"cisco_supported\",\"Cisco\",support_level==\"splunk_supported\",\"Splunk\",support_level==\"developer_supported\",\"Developer\",support_level==\"community_supported\",\"Community\",1==1,\"Not Supported\") | stats count as Count by Support | sort - Count"
			},
			"type": "ds.search"
		},
		"ds_table_soar": {
			"name": "Table SOAR Inventory",
			"options": {
				"query": "| savedsearch \"SCAN - SOAR Connector Inventory\""
			},
			"type": "ds.search"
		},
		"ds_table_addon_family": {
			"name": "Table Add-on Families",
			"options": {
				"query": "| savedsearch \"SCAN - Product Catalog - By Add-on Family\""
			},
			"type": "ds.search"
		},
		"ds_table_quality": {
			"name": "Table Data Quality Audit",
			"options": {
				"query": "| savedsearch \"SCAN - Data Quality - Missing Fields Audit\""
			},
			"type": "ds.search"
		},
		"ds_cisco_splunkbase": {
			"name": "Cisco Splunkbase Ecosystem",
			"options": {
				"query": "| savedsearch \"SCAN - Cisco Splunkbase Ecosystem\"",
				"queryParameters": {
					"earliest": "-15m",
					"latest": "now"
				}
			},
			"type": "ds.search"
		},
		"ds_kpi_cisco_live": {
			"name": "KPI Cisco Live Apps",
			"options": {
				"extend": "ds_cisco_splunkbase",
				"query": "| search is_archived=false type IN (\"app\",\"addon\") | stats count as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_cisco_archived": {
			"name": "KPI Cisco Archived Apps",
			"options": {
				"extend": "ds_cisco_splunkbase",
				"query": "| search is_archived=true | stats count as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_cisco_downloads": {
			"name": "KPI Cisco Total Downloads",
			"options": {
				"extend": "ds_cisco_splunkbase",
				"query": "| search is_archived=false | eval dl=tonumber(download_count) | stats sum(dl) as total"
			},
			"type": "ds.chain"
		},
		"ds_cisco_freshness": {
			"name": "Chart Cisco App Freshness",
			"options": {
				"extend": "ds_cisco_splunkbase",
				"query": "| search is_archived=false type IN (\"app\",\"addon\") | eval days=round((now()-updated_time)/86400) | eval health=case(days<=180,\"🟢 Fresh\",days<=365,\"🟡 Current\",days<=730,\"🟠 Aging\",1==1,\"🔴 Stale\") | stats count by health | sort - count"
			},
			"type": "ds.chain"
		},
		"ds_cisco_platform": {
			"name": "Chart Cisco Platform Compatibility",
			"options": {
				"extend": "ds_cisco_splunkbase",
				"query": "| search is_archived=false type IN (\"app\",\"addon\") | eval platform=case(like(product_compatibility,\"%Cloud%\") AND like(product_compatibility,\"%Enterprise%\"),\"Cloud + Enterprise\",like(product_compatibility,\"%Cloud%\"),\"Cloud Only\",like(product_compatibility,\"%Enterprise%\"),\"Enterprise Only\",1==1,\"Unknown\") | stats count by platform"
			},
			"type": "ds.chain"
		},
		"ds_cisco_top_downloads": {
			"name": "Chart Cisco Top Downloads",
			"options": {
				"extend": "ds_cisco_splunkbase",
				"query": "| search is_archived=false type IN (\"app\",\"addon\") | eval downloads=tonumber(download_count) | sort - downloads | head 10 | fields title downloads | rename title as App, downloads as Downloads"
			},
			"type": "ds.chain"
		},
		"ds_table_installed": {
			"name": "Table Installed Cisco Estate",
			"options": {
				"query": "| savedsearch \"SCAN - Installed Apps vs Catalog\""
			},
			"type": "ds.search"
		},
		"ds_cisco_version": {
			"name": "Table Cisco Version Tracker",
			"options": {
				"extend": "ds_cisco_splunkbase",
				"query": "| search is_archived=false | eval days=round((now()-updated_time)/86400) | eval staleness=case(days<=90,\"🟢 Fresh\",days<=365,\"🟡 Current\",days<=730,\"🟠 Aging\",1==1,\"🔴 Stale\") | eval updated_date=strftime(updated_time,\"%Y-%m-%d\") | table title type support app_version days staleness updated_date | sort - days | head 30"
			},
			"type": "ds.chain"
		},
		"ds_table_migration": {
			"name": "Table Migration Map",
			"options": {
				"query": "| savedsearch \"SCAN - Deprecated Migration Map\""
			},
			"type": "ds.search"
		},
		"ds_cisco_compliance": {
			"name": "Table Cisco Compliance",
			"options": {
				"extend": "ds_cisco_splunkbase",
				"query": "| search is_archived=false type IN (\"app\",\"addon\") | eval validation_status=case(passed_validation==\"true\" AND appinspect_passed==\"true\",\"✅ Fully Validated\",passed_validation==\"true\",\"✅ Passed Validation\",appinspect_passed==\"true\",\"⚠️ AppInspect Only\",1==1,\"❌ Not Validated\") | eval compliance=mvappend(if(fedramp_validation==\"yes\",\"FedRAMP\",null()),if(fips_compatibility==\"yes\",\"FIPS\",null())) | table title type support validation_status compliance app_version | sort 0 validation_status title"
			},
			"type": "ds.chain"
		},
		"ds_product_version_support": {
			"name": "Add-on Version Support Matrix",
			"options": {
				"query": "| savedsearch \"SCAN - Product Version Support Matrix\""
			},
			"type": "ds.search"
		},
		"ds_product_version_kpi": {
			"name": "KPI Compatible Add-ons",
			"options": {
				"extend": "ds_product_version_support",
				"query": "| where supports_$min_splunk_ver$=\"✅ YES\" | stats count as total"
			},
			"type": "ds.chain"
		},
		"ds_product_version_gap": {
			"name": "Add-ons WITHOUT Version Support",
			"options": {
				"query": "| savedsearch \"SCAN - Products WITHOUT Version Support\""
			},
			"type": "ds.search"
		},
		"ds_magic6_audit": {
			"name": "Magic Six Audit",
			"options": {
				"query": "| savedsearch \"SCAN - Magic Six Audit\""
			},
			"type": "ds.search"
		},
		"ds_magic6_kpi_complete": {
			"name": "KPI Magic Six Complete",
			"options": {
				"extend": "ds_magic6_audit",
				"query": "| search grade=\"🟢 Complete\" | stats dc(Sourcetype) as total"
			},
			"type": "ds.chain"
		},
		"ds_magic6_kpi_partial": {
			"name": "KPI Magic Six Partial",
			"options": {
				"extend": "ds_magic6_audit",
				"query": "| search grade=\"🟡 Partial\" OR grade=\"🟠 Minimal\" | stats dc(Sourcetype) as total"
			},
			"type": "ds.chain"
		},
		"ds_magic6_kpi_none": {
			"name": "KPI Magic Six None",
			"options": {
				"extend": "ds_magic6_audit",
				"query": "| search grade=\"🔴 None\" | stats dc(Sourcetype) as total"
			},
			"type": "ds.chain"
		},
		"ds_magic6_chart_grade": {
			"name": "Chart Magic Six Grade Distribution",
			"options": {
				"extend": "ds_magic6_audit",
				"query": "| stats dc(Sourcetype) as Count by grade | rename grade as Grade"
			},
			"type": "ds.chain"
		},
		"ds_magic6_chart_category": {
			"name": "Chart Magic Six by Category",
			"options": {
				"extend": "ds_magic6_audit",
				"query": "| stats avg(magic_six_count) as avg_score by Category | eval avg_score=round(avg_score,1) | rename avg_score as \"Avg Settings\" | sort - \"Avg Settings\""
			},
			"type": "ds.chain"
		}
	},
